import React from 'react';

import { MemoryRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

import { Provider } from 'react-redux';

import { store } from './store/store';

import { AppLayout } from './components/layout/AppLayout';

import { SimpleNotFoundPage } from '@linm-soft-org/linm-web-common-components';

import { isStandalone, showDevNav } from './dev/isStandalone';

import { StandaloneMockNav } from './standalone/StandaloneMockNav';

import { MemoryRouterSync } from './router/MemoryRouterSync';



const DevPage = React.lazy(() => import('./dev/DevPage'));



const DonHangListPage    = React.lazy(() => import('./pages/bh/DonHangListPage'));

const DonHangFormPage    = React.lazy(() => import('./pages/bh/DonHangFormPage'));

const HoaDonListPage     = React.lazy(() => import('./pages/bh/HoaDonListPage'));

const HoaDonFormPage     = React.lazy(() => import('./pages/bh/HoaDonFormPage'));

const TraHangBanListPage = React.lazy(() => import('./pages/bh/TraHangBanListPage'));

const TraHangBanFormPage = React.lazy(() => import('./pages/bh/TraHangBanFormPage'));

const HopDongListPage    = React.lazy(() => import('./pages/bh/HopDongListPage'));

const HopDongFormPage    = React.lazy(() => import('./pages/bh/HopDongFormPage'));

const HopDongDetailPage  = React.lazy(() => import('./pages/bh/HopDongDetailPage'));

const XuatHangPage       = React.lazy(() => import('./pages/bh/XuatHangPage'));

const XuatHangFormPage   = React.lazy(() => import('./pages/bh/XuatHangFormPage'));



const Suspense = ({ children }: { children: React.ReactNode }) => (

  <React.Suspense fallback={<div style={{ padding: '2rem' }}>Đang tải...</div>}>

    {children}

  </React.Suspense>

);



const AppShell = () => (

  <>

    {isStandalone && <StandaloneMockNav />}

    <AppLayout />

  </>

);



const initialPath =

  typeof window !== 'undefined'

    ? window.location.pathname + window.location.search || '/'

    : '/';



const AppRouter: React.FC = () => (

  <>

    <MemoryRouterSync />

    <Routes>

      <Route path="/" element={isStandalone ? <AppShell /> : <AppLayout />}>

        {showDevNav && (

          <>

            <Route index element={<Navigate to="/dev" replace />} />

            <Route path="dev" element={<Suspense><DevPage /></Suspense>} />

          </>

        )}

        <Route path="bh" element={<Navigate to="bh/dh" replace />} />

        <Route path="bh/dh"              element={<Suspense><DonHangListPage /></Suspense>} />

        <Route path="bh/dh/them"        element={<Suspense><DonHangFormPage /></Suspense>} />

        <Route path="bh/dh/:id"          element={<Suspense><DonHangFormPage /></Suspense>} />

        <Route path="bh/hoa-don"         element={<Suspense><HoaDonListPage /></Suspense>} />

        <Route path="bh/hoa-don/them"    element={<Suspense><HoaDonFormPage /></Suspense>} />

        <Route path="bh/hoa-don/:id"     element={<Suspense><HoaDonFormPage /></Suspense>} />

        <Route path="bh/tra-hang"       element={<Suspense><TraHangBanListPage /></Suspense>} />

        <Route path="bh/tra-hang/them"  element={<Suspense><TraHangBanFormPage /></Suspense>} />

        <Route path="bh/tra-hang/:id"   element={<Suspense><TraHangBanFormPage /></Suspense>} />

        <Route path="bh/hd"              element={<Suspense><HopDongListPage /></Suspense>} />

        <Route path="bh/hd/them"        element={<Suspense><HopDongFormPage /></Suspense>} />

        <Route path="bh/hd/:id/sua"      element={<Suspense><HopDongFormPage /></Suspense>} />

        <Route path="bh/hd/:id"          element={<Suspense><HopDongDetailPage /></Suspense>} />

        <Route path="bh/xuat-hang"      element={<Suspense><XuatHangPage /></Suspense>} />

        <Route path="bh/xuat-hang/them" element={<Suspense><XuatHangFormPage /></Suspense>} />

        <Route path="bh/xuat-hang/:id"   element={<Suspense><XuatHangFormPage /></Suspense>} />

        <Route path="*" element={<SimpleNotFoundPage showDevNav={showDevNav} homePath="/bh/dh" />} />

      </Route>

    </Routes>

  </>

);



const Root: React.FC = () => (

  <Provider store={store}>

    <Router initialEntries={[initialPath]} initialIndex={0}>

      <AppRouter />

    </Router>

  </Provider>

);



export default Root;

